  ('judicial-cf446b4c-moex-00404', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲是演員，依劇本應持道具槍作出開槍朝丙擊發之動作。乙明知其事，為利用甲殺死丙，暗中將該道具槍 調包為真槍。不知情之甲仍依劇本持槍朝丙射擊，導致丙死亡。下列敘述，何者正確？', '["甲成立故意殺人既遂罪", "乙成立故意殺人既遂罪", "甲成立殺人罪之幫助犯", "乙成立殺人罪之教唆犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00405', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關故意的敘述，下列何者錯誤？', '["對於構成犯罪之事實，預見其能發生而確信其不發生者，亦屬故意", "直接故意包含認識與意欲要素", "對於構成犯罪之事實，明知並有意使其發生，為直接故意", "對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，為未必故意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00406', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '公務員明知上級之命令違法，仍依所屬上級公務員命令而為其行為，其法律效果為何？', '["屬緊急避難，阻卻違法", "不得阻卻違法", "屬正當防衛，阻卻違法", "屬業務上正當行為，阻卻違法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
