  ('judicial-cf446b4c-moex-00408', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲與乙相處不睦，甲每日唸咒語詛咒乙發生意外，乙知悉後心神不寧，某日外出因未注意道路坑洞而跌傷。 甲之刑事責任為何？', '["不成立犯罪", "故意傷害罪", "恐嚇危安罪", "過失傷害罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
