  ('judicial-cf446b4c-moex-00410', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲欲對乙強制性交，甲壓制乙，脫去乙身上衣物進而強行舌吻時，乙用力咬傷甲之舌頭，讓甲因此離去。 有關本案之法律效果，下列敘述何者正確？', '["乙之行為屬緊急避難", "乙之行為屬正當防衛", "乙之行為屬避難過當", "乙之行為屬防衛過當"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00411', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲欲殺乙，明知乙在屋內而放火燒燬乙屋，致乙死亡。有關本案之敘述，下列何者正確？', '["甲成立放火致死罪", "甲成立放火殺人罪之結合犯", "甲成立放火罪與殺人罪，兩罪為想像競合", "甲成立放火罪與殺人罪，兩罪為法條競合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
